55	pub fn input_delete_word_left(s: &mut InputState) {
56	    let col = s.cursor_col;
57	    if col == 0 {
58	        return input_backspace(s);
59	    }
60	    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
61	    let mut i = col;
62	    while i > 0 && chars[i - 1] == ' ' {
63	        i -= 1;
