146	/// Move cursor one word left (Alt+Left) — stops at START of current word
147	pub fn input_move_word_left(s: &mut InputState) {
148	    clear_selection(s);
149	    if s.cursor_col == 0 {
150	        if s.cursor_line > 0 {
151	            s.cursor_line -= 1;
152	            s.cursor_col = s.lines[s.cursor_line].chars().count();
153	        }
154	        return;
155	    }
156	    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
157	    let mut i = s.cursor_col;
158	    // skip word chars backward (go to start of current word)
159	    while i > 0 && chars[i - 1] != ' ' { i -= 1; }
160	    // if already at start of word, skip spaces then go to start of previous word
161	    if i == s.cursor_col {
162	        while i > 0 && chars[i - 1] == ' ' { i -= 1; }
163	        while i > 0 && chars[i - 1] != ' ' { i -= 1; }
164	    }
165	    s.cursor_col = i;
166	}
167	
168	/// Move cursor one word right (Alt+Right) — stops at END of current word
169	pub fn input_move_word_right(s: &mut InputState) {
170	    clear_selection(s);
171	    let line_len = s.lines[s.cursor_line].chars().count();
172	    if s.cursor_col == line_len {
173	        if s.cursor_line + 1 < s.lines.len() {
174	            s.cursor_line += 1;
175	            s.cursor_col = 0;
176	        }
177	        return;
178	    }
179	    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
180	    let mut i = s.cursor_col;
181	    // skip leading spaces first
182	    while i < chars.len() && chars[i] == ' ' { i += 1; }
183	    // skip to end of word
184	    while i < chars.len() && chars[i] != ' ' { i += 1; }
185	    s.cursor_col = i;
186	}
