222	pub fn input_select_left(s: &mut InputState)       { extend_selection(s, input_move_left); }
223	pub fn input_select_right(s: &mut InputState)      { extend_selection(s, input_move_right); }
224	pub fn input_select_up(s: &mut InputState)         { extend_selection(s, input_move_up); }
225	pub fn input_select_down(s: &mut InputState)       { extend_selection(s, input_move_down); }
226	pub fn input_select_word_left(s: &mut InputState)  { extend_selection(s, input_move_word_left); }
227	pub fn input_select_word_right(s: &mut InputState) { extend_selection(s, input_move_word_right); }
