229	/// Place cursor at (line, col) from a mouse click, optionally extending selection.
230	pub fn input_click(s: &mut InputState, li: usize, ci: usize, extend: bool) {
231	    if extend {
232	        if s.selection_anchor.is_none() {
233	            s.selection_anchor = Some((s.cursor_line, s.cursor_col));
234	        }
235	        s.cursor_line = li;
236	        s.cursor_col = ci;
237	        let anchor = s.selection_anchor.unwrap();
238	        let cursor = (li, ci);
239	        if anchor == cursor {
240	            s.selection = None;
241	            s.selection_anchor = None;
242	        } else {
243	            let (start, end) = if anchor <= cursor { (anchor, cursor) } else { (cursor, anchor) };
244	            s.selection = Some(crate::state::Selection {
245	                start_line: start.0, start_col: start.1,
246	                end_line: end.0, end_col: end.1,
247	            });
248	        }
249	    } else {
250	        s.cursor_line = li;
251	        s.cursor_col = ci;
252	        s.selection = None;
253	        s.selection_anchor = None;
254	    }
255	}
