257	pub fn input_select_all(s: &mut InputState) {
258	    let last_line = s.lines.len() - 1;
259	    let last_col = s.lines[last_line].chars().count();
260	    s.selection = Some(Selection {
261	        start_line: 0,
262	        start_col: 0,
263	        end_line: last_line,
264	        end_col: last_col,
265	    });
266	    s.cursor_line = last_line;
267	    s.cursor_col = last_col;
268	}
