276	fn delete_selection(s: &mut InputState, sel: &Selection) {
277	    let (sl, sc, el, ec) =
278	        if (sel.start_line, sel.start_col) < (sel.end_line, sel.end_col) {
279	            (sel.start_line, sel.start_col, sel.end_line, sel.end_col)
280	        } else {
281	            (sel.end_line, sel.end_col, sel.start_line, sel.start_col)
282	        };
283	    if sl == el {
284	        let line = &mut s.lines[sl];
285	        let b_start = char_to_byte_idx(line, sc);
286	        let b_end = char_to_byte_idx(line, ec);
287	        line.drain(b_start..b_end);
288	    } else {
289	        let ec_byte = char_to_byte_idx(&s.lines[el], ec);
290	        let suffix = s.lines[el][ec_byte..].to_string();
291	        let sc_byte = char_to_byte_idx(&s.lines[sl], sc);
292	        s.lines[sl].truncate(sc_byte);
293	        s.lines[sl].push_str(&suffix);
294	        s.lines.drain(sl + 1..=el);
295	    }
296	    s.cursor_line = sl;
297	    s.cursor_col = sc;
298	}
