327	pub fn render_input(
328	    f: &mut Frame,
329	    state: &InputState,
330	    area: ratatui::layout::Rect,
331	    focused: bool,
332	    input_rect_out: &mut ratatui::layout::Rect,
333	) {
334	    let border_style = if focused {
335	        Style::default().fg(Color::Cyan)
336	    } else {
337	        Style::default().fg(Color::DarkGray)
338	    };
339	
340	    let block = Block::default()
341	        .borders(Borders::ALL)
342	        .border_type(BorderType::Rounded)
343	        .border_style(border_style);
344	
345	    let inner = block.inner(area);
346	    *input_rect_out = inner; // store for mouse click mapping
347	    f.render_widget(block, area);
348	
349	    let visible_height = inner.height as usize;
350	    let total_lines = state.lines.len();
351	
352	    // Scroll to keep cursor visible
353	    let scroll_offset = if total_lines <= visible_height {
354	        0
355	    } else if state.cursor_line < state.scroll_offset {
356	        state.cursor_line
357	    } else if state.cursor_line >= state.scroll_offset + visible_height {
358	        state.cursor_line.saturating_sub(visible_height - 1)
359	    } else {
360	        state.scroll_offset
361	    };
362	
363	    let text_lines: Vec<Line> = state
364	        .lines
365	        .iter()
366	        .enumerate()
367	        .skip(scroll_offset)
368	        .take(visible_height)
369	        .map(|(li, line)| {
370	            let mut spans = Vec::new();
371	
372	            // "> " prefix on first line, "  " on subsequent
373	            let prefix = if li == 0 { "> " } else { "  " };
374	            spans.push(Span::styled(prefix, Style::default().fg(Color::DarkGray)));
375	
376	            let chars: Vec<char> = line.chars().collect();
377	            for (ci, &ch) in chars.iter().enumerate() {
378	                let is_cursor = li == state.cursor_line && ci == state.cursor_col;
379	                let in_sel = in_selection(state, li, ci);
380	                let style = if is_cursor || in_sel {
381	                    Style::default().bg(Color::White).fg(Color::Black)
382	                } else {
383	                    Style::default().fg(Color::White)
384	                };
385	                spans.push(Span::styled(ch.to_string(), style));
386	            }
387	            // Cursor at end of line
388	            if li == state.cursor_line && state.cursor_col == chars.len() {
389	                spans.push(Span::styled(" ", Style::default().bg(Color::White).fg(Color::Black)));
390	            }
391	            Line::from(spans)
392	        })
393	        .collect();
394	
395	    let para = Paragraph::new(text_lines);
396	    f.render_widget(para, inner);
397	}
