399	fn in_selection(state: &InputState, li: usize, ci: usize) -> bool {
400	    let Some(sel) = &state.selection else { return false };
401	    let (sl, sc, el, ec) = if (sel.start_line, sel.start_col) < (sel.end_line, sel.end_col) {
402	        (sel.start_line, sel.start_col, sel.end_line, sel.end_col)
403	    } else {
404	        (sel.end_line, sel.end_col, sel.start_line, sel.start_col)
405	    };
406	    if li < sl || li > el { false }
407	    else if li == sl && li == el { ci >= sc && ci < ec }
408	    else if li == sl { ci >= sc }
409	    else if li == el { ci < ec }
410	    else { true }
411	}
412	
413	/// Advance one position in the text (col+1, or next line start).
414	fn advance_pos(lines: &[String], li: usize, ci: usize) -> (usize, usize) {
415	    let line_len = lines[li].chars().count();
416	    if ci < line_len { (li, ci + 1) }
417	    else if li + 1 < lines.len() { (li + 1, 0) }
418	    else { (li, ci) }
419	}
