use ratatui::{
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, BorderType, Borders, Paragraph},
    Frame,
};

use crate::state::{InputState, Selection};

fn clear_selection(s: &mut InputState) {
    s.selection = None;
    s.selection_anchor = None;
}

pub fn input_char(s: &mut InputState, c: char) {
    clear_selection(s);
    let line = &mut s.lines[s.cursor_line];
    let byte_idx = char_to_byte_idx(line, s.cursor_col);
    line.insert(byte_idx, c);
    s.cursor_col += 1;
}

pub fn input_backspace(s: &mut InputState) {
    if let Some(sel) = s.selection.take() {
        s.selection_anchor = None;
        delete_selection(s, &sel);
        return;
    }
    if s.cursor_col > 0 {
        let line = &mut s.lines[s.cursor_line];
        let byte_idx = char_to_byte_idx(line, s.cursor_col);
        let prev = prev_char_boundary(line, byte_idx);
        line.drain(prev..byte_idx);
        s.cursor_col -= 1;
    } else if s.cursor_line > 0 {
        let removed = s.lines.remove(s.cursor_line);
        s.cursor_line -= 1;
        let prev_len = s.lines[s.cursor_line].chars().count();
        s.lines[s.cursor_line].push_str(&removed);
        s.cursor_col = prev_len;
    }
}

pub fn input_newline(s: &mut InputState) {
    clear_selection(s);
    let line = s.lines[s.cursor_line].clone();
    let byte_idx = char_to_byte_idx(&line, s.cursor_col);
    let rest = line[byte_idx..].to_string();
    s.lines[s.cursor_line].truncate(byte_idx);
    s.cursor_line += 1;
    s.lines.insert(s.cursor_line, rest);
    s.cursor_col = 0;
}

pub fn input_delete_word_left(s: &mut InputState) {
    let col = s.cursor_col;
    if col == 0 {
        return input_backspace(s);
    }
    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
    let mut i = col;
    while i > 0 && chars[i - 1] == ' ' {
        i -= 1;
    }
    while i > 0 && chars[i - 1] != ' ' {
        i -= 1;
    }
    let line = &mut s.lines[s.cursor_line];
    let b_start = char_to_byte_idx(line, i);
    let b_end = char_to_byte_idx(line, col);
    line.drain(b_start..b_end);
    s.cursor_col = i;
}

pub fn input_delete_word_right(s: &mut InputState) {
    let col = s.cursor_col;
    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
    let mut i = col;
    while i < chars.len() && chars[i] == ' ' {
        i += 1;
    }
    while i < chars.len() && chars[i] != ' ' {
        i += 1;
    }
    let line = &mut s.lines[s.cursor_line];
    let b_start = char_to_byte_idx(line, col);
    let b_end = char_to_byte_idx(line, i);
    line.drain(b_start..b_end);
}

pub fn input_delete_line(s: &mut InputState) {
    let col = s.cursor_col;
    if col == 0 {
        if s.cursor_line > 0 {
            s.lines.remove(s.cursor_line);
            s.cursor_line -= 1;
            s.cursor_col = s.lines[s.cursor_line].chars().count();
        }
        return;
    }
    let line = &mut s.lines[s.cursor_line];
    let byte_idx = char_to_byte_idx(line, col);
    line.drain(..byte_idx);
    s.cursor_col = 0;
}

pub fn input_move_left(s: &mut InputState) {
    clear_selection(s);
    if s.cursor_col > 0 {
        s.cursor_col -= 1;
    } else if s.cursor_line > 0 {
        s.cursor_line -= 1;
        s.cursor_col = s.lines[s.cursor_line].chars().count();
    }
}

pub fn input_move_right(s: &mut InputState) {
    clear_selection(s);
    let line_len = s.lines[s.cursor_line].chars().count();
    if s.cursor_col < line_len {
        s.cursor_col += 1;
    } else if s.cursor_line + 1 < s.lines.len() {
        s.cursor_line += 1;
        s.cursor_col = 0;
    }
}

pub fn input_move_up(s: &mut InputState) {
    clear_selection(s);
    if s.cursor_line > 0 {
        s.cursor_line -= 1;
        let line_len = s.lines[s.cursor_line].chars().count();
        s.cursor_col = s.cursor_col.min(line_len);
    }
}

pub fn input_move_down(s: &mut InputState) {
    clear_selection(s);
    if s.cursor_line + 1 < s.lines.len() {
        s.cursor_line += 1;
        let line_len = s.lines[s.cursor_line].chars().count();
        s.cursor_col = s.cursor_col.min(line_len);
    }
}

/// Move cursor one word left (Alt+Left) — stops at START of current word
pub fn input_move_word_left(s: &mut InputState) {
    clear_selection(s);
    if s.cursor_col == 0 {
        if s.cursor_line > 0 {
            s.cursor_line -= 1;
            s.cursor_col = s.lines[s.cursor_line].chars().count();
        }
        return;
    }
    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
    let mut i = s.cursor_col;
    // skip word chars backward (go to start of current word)
    while i > 0 && chars[i - 1] != ' ' { i -= 1; }
    // if already at start of word, skip spaces then go to start of previous word
    if i == s.cursor_col {
        while i > 0 && chars[i - 1] == ' ' { i -= 1; }
        while i > 0 && chars[i - 1] != ' ' { i -= 1; }
    }
    s.cursor_col = i;
}

/// Move cursor one word right (Alt+Right) — stops at END of current word
pub fn input_move_word_right(s: &mut InputState) {
    clear_selection(s);
    let line_len = s.lines[s.cursor_line].chars().count();
    if s.cursor_col == line_len {
        if s.cursor_line + 1 < s.lines.len() {
            s.cursor_line += 1;
            s.cursor_col = 0;
        }
        return;
    }
    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
    let mut i = s.cursor_col;
    // skip leading spaces first
    while i < chars.len() && chars[i] == ' ' { i += 1; }
    // skip to end of word
    while i < chars.len() && chars[i] != ' ' { i += 1; }
    s.cursor_col = i;
}

/// Set anchor if not set, move cursor, update selection.
/// Selection bounds are stored to match the visually highlighted region:
/// - Right (anchor <= cursor): [anchor, cursor) — anchor char included, cursor char excluded
/// - Left  (cursor < anchor):  [cursor+1, anchor+1) — current char included, cursor char excluded
fn extend_selection(s: &mut InputState, move_fn: fn(&mut InputState)) {
    if s.selection_anchor.is_none() {
        s.selection_anchor = Some((s.cursor_line, s.cursor_col));
    }
    let anchor = s.selection_anchor;
    move_fn(s); // clears selection_anchor, restore after
    s.selection_anchor = anchor;
    if let Some(anchor_pt) = s.selection_anchor {
        let cursor = (s.cursor_line, s.cursor_col);
        if anchor_pt == cursor {
            s.selection = None;
            s.selection_anchor = None;
        } else if cursor < anchor_pt {
            // Left-extending: visually highlight (cursor, anchor] = [cursor+1, anchor+1)
            let start = advance_pos(&s.lines, cursor.0, cursor.1);
            let end   = advance_pos(&s.lines, anchor_pt.0, anchor_pt.1);
            s.selection = Some(crate::state::Selection {
                start_line: start.0, start_col: start.1,
                end_line:   end.0,   end_col:   end.1,
            });
        } else {
            // Right-extending: visually highlight [anchor, cursor)
            s.selection = Some(crate::state::Selection {
                start_line: anchor_pt.0, start_col: anchor_pt.1,
                end_line:   cursor.0,   end_col:   cursor.1,
            });
        }
    }
}

pub fn input_select_left(s: &mut InputState)       { extend_selection(s, input_move_left); }
pub fn input_select_right(s: &mut InputState)      { extend_selection(s, input_move_right); }
pub fn input_select_up(s: &mut InputState)         { extend_selection(s, input_move_up); }
pub fn input_select_down(s: &mut InputState)       { extend_selection(s, input_move_down); }
pub fn input_select_word_left(s: &mut InputState)  { extend_selection(s, input_move_word_left); }
pub fn input_select_word_right(s: &mut InputState) { extend_selection(s, input_move_word_right); }

/// Place cursor at (line, col) from a mouse click, optionally extending selection.
pub fn input_click(s: &mut InputState, li: usize, ci: usize, extend: bool) {
    if extend {
        if s.selection_anchor.is_none() {
            s.selection_anchor = Some((s.cursor_line, s.cursor_col));
        }
        s.cursor_line = li;
        s.cursor_col = ci;
        let anchor = s.selection_anchor.unwrap();
        let cursor = (li, ci);
        if anchor == cursor {
            s.selection = None;
            s.selection_anchor = None;
        } else {
            let (start, end) = if anchor <= cursor { (anchor, cursor) } else { (cursor, anchor) };
            s.selection = Some(crate::state::Selection {
                start_line: start.0, start_col: start.1,
                end_line: end.0, end_col: end.1,
            });
        }
    } else {
        s.cursor_line = li;
        s.cursor_col = ci;
        s.selection = None;
        s.selection_anchor = None;
    }
}

pub fn input_select_all(s: &mut InputState) {
    let last_line = s.lines.len() - 1;
    let last_col = s.lines[last_line].chars().count();
    s.selection = Some(Selection {
        start_line: 0,
        start_col: 0,
        end_line: last_line,
        end_col: last_col,
    });
    s.cursor_line = last_line;
    s.cursor_col = last_col;
}

pub fn input_end_of_text(s: &mut InputState) {
    s.selection = None;
    s.cursor_line = s.lines.len() - 1;
    s.cursor_col = s.lines[s.cursor_line].chars().count();
}

fn delete_selection(s: &mut InputState, sel: &Selection) {
    let (sl, sc, el, ec) =
        if (sel.start_line, sel.start_col) < (sel.end_line, sel.end_col) {
            (sel.start_line, sel.start_col, sel.end_line, sel.end_col)
        } else {
            (sel.end_line, sel.end_col, sel.start_line, sel.start_col)
        };
    if sl == el {
        let line = &mut s.lines[sl];
        let b_start = char_to_byte_idx(line, sc);
        let b_end = char_to_byte_idx(line, ec);
        line.drain(b_start..b_end);
    } else {
        let ec_byte = char_to_byte_idx(&s.lines[el], ec);
        let suffix = s.lines[el][ec_byte..].to_string();
        let sc_byte = char_to_byte_idx(&s.lines[sl], sc);
        s.lines[sl].truncate(sc_byte);
        s.lines[sl].push_str(&suffix);
        s.lines.drain(sl + 1..=el);
    }
    s.cursor_line = sl;
    s.cursor_col = sc;
}

fn char_to_byte_idx(s: &str, char_idx: usize) -> usize {
    s.char_indices()
        .nth(char_idx)
        .map(|(b, _)| b)
        .unwrap_or(s.len())
}

fn prev_char_boundary(s: &str, byte_idx: usize) -> usize {
    let mut i = byte_idx.saturating_sub(1);
    while i > 0 && !s.is_char_boundary(i) {
        i -= 1;
    }
    i
}

/// Compute (line_idx, col_idx) from a mouse click at (col, row) inside the input inner area.
pub fn cursor_from_mouse(state: &InputState, area: ratatui::layout::Rect, col: u16, row: u16) -> (usize, usize) {
    // Inner area starts 1 col in (for border), and first col is ">" prefix (2 chars)
    let prefix_w = 2usize; // "> "
    let li = (row.saturating_sub(area.y)) as usize;
    let li = li.min(state.lines.len().saturating_sub(1));
    let rel_col = (col.saturating_sub(area.x)) as usize;
    let ci = rel_col.saturating_sub(prefix_w);
    let line_len = state.lines[li].chars().count();
    (li, ci.min(line_len))
}

pub fn render_input(
    f: &mut Frame,
    state: &InputState,
    area: ratatui::layout::Rect,
    focused: bool,
    input_rect_out: &mut ratatui::layout::Rect,
) {
    let border_style = if focused {
        Style::default().fg(Color::Cyan)
    } else {
        Style::default().fg(Color::DarkGray)
    };

    let block = Block::default()
        .borders(Borders::ALL)
        .border_type(BorderType::Rounded)
        .border_style(border_style);

    let inner = block.inner(area);
    *input_rect_out = inner; // store for mouse click mapping
    f.render_widget(block, area);

    let visible_height = inner.height as usize;
    let total_lines = state.lines.len();

    // Scroll to keep cursor visible
    let scroll_offset = if total_lines <= visible_height {
        0
    } else if state.cursor_line < state.scroll_offset {
        state.cursor_line
    } else if state.cursor_line >= state.scroll_offset + visible_height {
        state.cursor_line.saturating_sub(visible_height - 1)
    } else {
        state.scroll_offset
    };

    let text_lines: Vec<Line> = state
        .lines
        .iter()
        .enumerate()
        .skip(scroll_offset)
        .take(visible_height)
        .map(|(li, line)| {
            let mut spans = Vec::new();

            // "> " prefix on first line, "  " on subsequent
            let prefix = if li == 0 { "> " } else { "  " };
            spans.push(Span::styled(prefix, Style::default().fg(Color::DarkGray)));

            let chars: Vec<char> = line.chars().collect();
            for (ci, &ch) in chars.iter().enumerate() {
                let is_cursor = li == state.cursor_line && ci == state.cursor_col;
                let in_sel = in_selection(state, li, ci);
                let style = if is_cursor || in_sel {
                    Style::default().bg(Color::White).fg(Color::Black)
                } else {
                    Style::default().fg(Color::White)
                };
                spans.push(Span::styled(ch.to_string(), style));
            }
            // Cursor at end of line
            if li == state.cursor_line && state.cursor_col == chars.len() {
                spans.push(Span::styled(" ", Style::default().bg(Color::White).fg(Color::Black)));
            }
            Line::from(spans)
        })
        .collect();

    let para = Paragraph::new(text_lines);
    f.render_widget(para, inner);
}

fn in_selection(state: &InputState, li: usize, ci: usize) -> bool {
    let Some(sel) = &state.selection else { return false };
    let (sl, sc, el, ec) = if (sel.start_line, sel.start_col) < (sel.end_line, sel.end_col) {
        (sel.start_line, sel.start_col, sel.end_line, sel.end_col)
    } else {
        (sel.end_line, sel.end_col, sel.start_line, sel.start_col)
    };
    if li < sl || li > el { false }
    else if li == sl && li == el { ci >= sc && ci < ec }
    else if li == sl { ci >= sc }
    else if li == el { ci < ec }
    else { true }
}

/// Advance one position in the text (col+1, or next line start).
fn advance_pos(lines: &[String], li: usize, ci: usize) -> (usize, usize) {
    let line_len = lines[li].chars().count();
    if ci < line_len { (li, ci + 1) }
    else if li + 1 < lines.len() { (li + 1, 0) }
    else { (li, ci) }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::state::InputState;

    fn state_with(text: &str) -> InputState {
        let mut s = InputState::new();
        for (i, line) in text.split('\n').enumerate() {
            if i == 0 {
                s.lines[0] = line.to_string();
            } else {
                s.lines.push(line.to_string());
            }
        }
        s.cursor_line = s.lines.len() - 1;
        s.cursor_col = s.lines.last().map(|l| l.chars().count()).unwrap_or(0);
        s
    }

    #[test]
    fn insert_char() {
        let mut s = InputState::new();
        input_char(&mut s, 'H');
        input_char(&mut s, 'i');
        assert_eq!(s.lines[0], "Hi");
        assert_eq!(s.cursor_col, 2);
    }

    #[test]
    fn backspace_at_start_of_line_merges() {
        let mut s = state_with("foo\nbar");
        s.cursor_line = 1;
        s.cursor_col = 0;
        input_backspace(&mut s);
        assert_eq!(s.lines.len(), 1);
        assert_eq!(s.lines[0], "foobar");
        assert_eq!(s.cursor_col, 3);
    }

    #[test]
    fn shift_enter_inserts_newline() {
        let mut s = state_with("hello");
        input_newline(&mut s);
        assert_eq!(s.lines.len(), 2);
        assert_eq!(s.cursor_line, 1);
        assert_eq!(s.cursor_col, 0);
    }

    #[test]
    fn word_delete_left() {
        let mut s = state_with("hello world");
        input_delete_word_left(&mut s);
        assert_eq!(s.lines[0], "hello ");
    }

    #[test]
    fn line_delete() {
        let mut s = state_with("prefix text");
        s.cursor_col = 7;
        input_delete_line(&mut s);
        assert_eq!(s.lines[0], "text");
    }
}

