61	    app.skills.repo = skill_set.repo.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
62	    app.skills.user = skill_set.user.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
63	    app.skills.global = skill_set.global.iter().map(|s| state::SkillEntry { name: s.name.clone(), path: s.path.clone(), overridden: s.overridden }).collect();
