78	async fn run_loop(
79	    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
80	    state: &mut AppState,
81	) -> Result<()> {
82	    let settings = clui_config::Settings::from_env();
83	    let (event_tx, mut event_rx) = mpsc::channel::<AppEvent>(256);
84	
85	    // Spawn agent for initial tab (uses claude CLI subprocess, no API key needed)
86	    {
87	        let tx = agent_task::spawn_agent(
88	            state.tabs[0].id.clone(),
89	            state.cwd.to_string_lossy().to_string(),
90	            settings.default_model.clone(),
91	            event_tx.clone(),
92	        );
93	        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
94	            *agent_tx = Some(tx);
95	        }
96	    }
97	
98	    // Initial git refresh
99	    let _ = event_tx.send(AppEvent::GitRefresh).await;
100	
101	    // Spawn git watcher
102	    let etx_git = event_tx.clone();
103	    tokio::spawn(async move {
104	        loop {
105	            tokio::time::sleep(Duration::from_secs(5)).await;
106	            let _ = etx_git.send(AppEvent::GitRefresh).await;
107	        }
108	    });
109	
110	    // Watch cwd for file system changes — refresh file tree instantly
111	    {
112	        use notify::{Config, RecommendedWatcher, RecursiveMode, Watcher};
113	        use std::sync::mpsc as std_mpsc;
114	
115	        let watch_dir = state.cwd.clone();
116	        let etx_files = event_tx.clone();
117	
118	        tokio::task::spawn_blocking(move || {
119	            let (tx, rx) = std_mpsc::channel();
120	            let mut watcher = match RecommendedWatcher::new(tx, Config::default()) {
121	                Ok(w) => w,
122	                Err(_) => return,
123	            };
124	            if watcher.watch(&watch_dir, RecursiveMode::Recursive).is_err() {
