        if let Some(tab) = state.active_tab_mut() {
            let text = tab.input.text();
            if !text.is_empty() {
                tab.messages.push(crate::state::ChatMessage {
                    role: crate::state::MessageRole::User,
                    content: text.clone(),
                });
                tab.pending_prompt = Some(text);
                tab.input = crate::state::InputState::new();
            }
        }
    } else if code == KC::Char('d') && modifiers.contains(KM::CONTROL) {
        if let Some(tab) = state.tabs.get_mut(state.active_tab) {
            if matches!(tab.kind, crate::state::TabKind::Chat { .. }) {
                tab.chat_scroll += 10;
            }
        }
    } else if code == KC::Char('b') && modifiers.contains(KM::CONTROL) {
        if let Some(tab) = state.tabs.get_mut(state.active_tab) {
            if matches!(tab.kind, crate::state::TabKind::Chat { .. }) {
                tab.chat_scroll = tab.chat_scroll.saturating_sub(10);
            }
        }
    } else if let Some(tab) = state.active_tab_mut() {
        let s = &mut tab.input;
        match (code, modifiers) {
            // Newline: Shift+Enter, Alt+Enter, or Ctrl+J (most reliable across terminals)
            (KC::Enter, m) if m.contains(KM::SHIFT) || m.contains(KM::ALT) => {
                input_newline(s);
            }
            (KC::Char('j'), m) if m.contains(KM::CONTROL) => {
                input_newline(s);
            }
            // Shift+Alt+Arrow — select word by word
            (KC::Left,  m) if m.contains(KM::SHIFT) && m.contains(KM::ALT) => input_select_word_left(s),
            (KC::Right, m) if m.contains(KM::SHIFT) && m.contains(KM::ALT) => input_select_word_right(s),
            // Shift+Arrow — select char by char
            (KC::Left,  m) if m.contains(KM::SHIFT) => input_select_left(s),
            (KC::Right, m) if m.contains(KM::SHIFT) => input_select_right(s),
            (KC::Up,    m) if m.contains(KM::SHIFT) => input_select_up(s),
            (KC::Down,  m) if m.contains(KM::SHIFT) => input_select_down(s),
            // Alt+Arrow — move word by word
            // Also handle Alt+b/f: what macOS Terminal sends for Option+Left/Right
            (KC::Left,  m) if m.contains(KM::ALT) => input_move_word_left(s),
            (KC::Right, m) if m.contains(KM::ALT) => input_move_word_right(s),
            (KC::Char('b'), m) if m.contains(KM::ALT) => input_move_word_left(s),
            (KC::Char('f'), m) if m.contains(KM::ALT) => input_move_word_right(s),
            // Shift+Alt+b/f for word selection (macOS Terminal fallback)
            (KC::Char('B'), m) if m.contains(KM::ALT) => input_select_word_left(s),
            (KC::Char('F'), m) if m.contains(KM::ALT) => input_select_word_right(s),
            // Regular movement
            (KC::Left,  _) => input_move_left(s),
            (KC::Right, _) => input_move_right(s),
            (KC::Up,    _) => input_move_up(s),
            (KC::Down,  _) => input_move_down(s),
            // Deletion
            (KC::Backspace, m) if m.contains(KM::ALT) => input_delete_word_left(s),
            (KC::Backspace, _) => input_backspace(s),
            (KC::Delete, m) if m.contains(KM::ALT) => input_delete_word_right(s),
            (KC::Delete, _) => input_delete_word_right(s),
            // Ctrl shortcuts
            (KC::Char('a'), m) if m.contains(KM::CONTROL) => input_select_all(s),
            (KC::Char('a'), m) if m.contains(KM::ALT) => input_select_all(s),
            (KC::Char('e'), m) if m.contains(KM::CONTROL) => input_end_of_text(s),
            (KC::Char('u'), m) if m.contains(KM::CONTROL) => input_delete_line(s),
            (KC::Char(c), m) if !m.contains(KM::CONTROL) && !m.contains(KM::ALT) && !m.contains(KM::SUPER) => {
                input_char(s, c);
            }
            _ => {}
        }
    }
