/// Compute (line_idx, col_idx) from a mouse click at (col, row) inside the input inner area.
pub fn cursor_from_mouse(state: &InputState, area: ratatui::layout::Rect, col: u16, row: u16) -> (usize, usize) {
    let prefix_w = 2usize; // "> " or "  "
    let wrap_width = (area.width as usize).saturating_sub(prefix_w);
    let wrap_width = wrap_width.max(1);

    let visual_row = (row.saturating_sub(area.y)) as usize;
    let rel_col = (col.saturating_sub(area.x)) as usize;
    let char_col = rel_col.saturating_sub(prefix_w);

    // Walk visual rows to find which logical line + offset
    let mut vrow = 0usize;
    for (li, line) in state.lines.iter().enumerate() {
        let line_len = line.chars().count();
        let wrapped_rows = if line_len == 0 { 1 } else { (line_len + wrap_width - 1) / wrap_width };
        if visual_row < vrow + wrapped_rows {
            // Within this logical line
            let sub_row = visual_row - vrow;
            let ci = sub_row * wrap_width + char_col;
            return (li, ci.min(line_len));
        }
        vrow += wrapped_rows;
    }
    // Past end — place at end of last line
    let last = state.lines.len().saturating_sub(1);
    (last, state.lines[last].chars().count())
}

/// Count how many visual rows all lines take when wrapped to a given width.
pub fn visual_line_count(state: &InputState, wrap_width: usize) -> usize {
    let w = wrap_width.max(1);
    state.lines.iter().map(|line| {
        let len = line.chars().count();
        if len == 0 { 1 } else { (len + w - 1) / w }
    }).sum()
}

