use ratatui::{
    layout::Constraint,
    style::{Color, Style},
    widgets::{Block, BorderType, Borders},
    Frame,
};
use crate::state::{AppState, DragTarget, TabKind};

pub fn render(f: &mut Frame, state: &mut AppState) {
    let area = f.area();
    let cols = layout::compute_columns(&state.layout, area);

    // Store border positions for mouse hit-testing
    state.last_left_border_col = cols.left_border_col;
    state.last_right_border_col = cols.right_border_col;

    // Compute border colors based on drag/hover/focus state
    let left_focused = matches!(state.layout.focus, crate::state::Focus::LeftSidebar);
    let right_focused = matches!(state.layout.focus, crate::state::Focus::RightSidebar);

    let left_border_color = if state.layout.drag.as_ref().map(|d| d.target == DragTarget::LeftBorder).unwrap_or(false) {
        Color::Cyan
    } else if state.hover_left_border {
        Color::Yellow
    } else if left_focused {
        Color::Cyan
    } else {
        Color::DarkGray
    };
    let right_border_color = if state.layout.drag.as_ref().map(|d| d.target == DragTarget::RightBorder).unwrap_or(false) {
        Color::Cyan
    } else if state.hover_right_border {
        Color::Yellow
    } else if right_focused {
        Color::Cyan
    } else {
        Color::DarkGray
    };

    layout::render_tab_bar(f, state, cols.tab_bar);

    if state.layout.left_visible {
        sidebar_left::render_left_sidebar(f, state, cols.left, left_border_color);
    }

    // Compute dynamic input height: content lines + 2 (border), capped at 50% of center
    let input_content_lines = state.tabs.get(state.active_tab)
        .map(|t| t.input.lines.len())
        .unwrap_or(1);
    let max_input_height = (cols.center.height / 2) as usize;
    let input_height = (input_content_lines + 2).clamp(5, max_input_height) as u16;

    let center_layout = ratatui::layout::Layout::vertical([
        Constraint::Length(3),          // info bar
        Constraint::Min(3),             // chat
        Constraint::Length(3),          // context bar
        Constraint::Length(input_height), // input (dynamic)
    ])
    .split(cols.center);

    // Store chat rect for scroll routing
    state.chat_area_rect = center_layout[1];

    let input_focused = matches!(state.layout.focus, crate::state::Focus::Input);
    let chat_focused  = matches!(state.layout.focus, crate::state::Focus::Chat);

    // Clone what we need to avoid borrow conflicts
    let active_idx = state.active_tab;
    if let Some(tab) = state.tabs.get_mut(active_idx) {
        match &tab.kind {
            TabKind::Chat { .. } => {
                let info_tab = tab.clone();
                let cwd = state.cwd.clone();
                let chat_sel = state.chat_selection.clone();
                info_bar::render_info_bar(f, Some(&info_tab), center_layout[0]);
                chat::render_chat(f, tab, center_layout[1], chat_focused, &mut state.chat_links, &cwd, &chat_sel, &mut state.chat_row_text);
                // Update input scroll_offset to keep cursor visible
                {
                    let input_inner_height = input_height.saturating_sub(2) as usize; // minus border
                    let inp = &mut state.tabs.get_mut(active_idx).unwrap().input;
                    if inp.cursor_line < inp.scroll_offset {
                        inp.scroll_offset = inp.cursor_line;
                    } else if inp.cursor_line >= inp.scroll_offset + input_inner_height {
                        inp.scroll_offset = inp.cursor_line.saturating_sub(input_inner_height - 1);
                    }
                }
                let ctx_tab = state.tabs.get(active_idx).unwrap();
                context_bar::render_context_bar(f, Some(ctx_tab), center_layout[2]);
                let input_snap = ctx_tab.input.clone();
                input::render_input(f, &input_snap, center_layout[3], input_focused, &mut state.input_area_rect);
            }
            TabKind::FileViewer { path, content, scroll, .. } => {
                let (p, c, s) = (path.clone(), content.clone(), *scroll);
                file_viewer::render_file_viewer(f, &p, &c, s, cols.center);
            }
            TabKind::DiffViewer { path, diff, staged, scroll } => {
                let (p, d, st, sc) = (path.clone(), diff.clone(), *staged, *scroll);
                diff_viewer::render_diff_viewer(f, &p, &d, st, sc, cols.center);
            }
        }
    }

    if state.layout.right_visible {
        sidebar_right::render_right_sidebar(f, state, cols.right, right_border_color);
    }
    // also need to update skills: state is &mut so fine

    // Notifications overlay
    notification::render_notifications(f, &state.notifications, area);
    // Confirm dialog overlay
    if let Some(dialog) = &state.confirm_dialog {
        confirm::render_confirm(f, dialog, area);
    }
}

