// Update input scroll_offset to keep cursor visible (visual rows)
{
    let input_inner_height = input_height.saturating_sub(2) as usize;
    let inp = &mut state.tabs.get_mut(active_idx).unwrap().input;
    // Compute cursor visual row
    let mut cursor_vrow = 0usize;
    for (li, line) in inp.lines.iter().enumerate() {
        let len = line.chars().count();
        let rows = if len == 0 { 1 } else { (len + est_wrap_w - 1) / est_wrap_w };
        if li == inp.cursor_line {
            let sub = inp.cursor_col / est_wrap_w.max(1);
            cursor_vrow += sub;
            break;
        }
        cursor_vrow += rows;
    }
    if cursor_vrow < inp.scroll_offset {
        inp.scroll_offset = cursor_vrow;
    } else if cursor_vrow >= inp.scroll_offset + input_inner_height {
        inp.scroll_offset = cursor_vrow.saturating_sub(input_inner_height - 1);
    }
}

